// Wrap as { docs: [...] } so the frontend's recursive extractor picks it up cleanly.
const docs = $input.all().map(i => i.json);
return [{ json: { docs } }];

// Accept file_id from body, query string or `id`.
const b = $input.first().json || {};
const body = b.body || b;
const q = b.query || b.queryString || {};
const fileId = body.file_id || body.id || q.file_id || q.id;
if (!fileId) throw new Error('file_id is required');
return { fileId };

