// Normalize payload from front-end (sends JSON with file_id/title/code/etc.)
const b = $input.first().json || {};
const body = b.body || b;
const payload = {
  file_id:        body.file_id || body.id,
  title:          body.title || body.file_id || 'Sem título',
  code:           body.code || null,
  url:            body.url || null,
  source:         body.source || 'upload',
  mime_type:      body.mime_type || null,
  category_id:    body.category_id || null,
  category_code:  body.category_code || null,
  schema:         body.schema ? JSON.stringify(body.schema) : null
};
if (!payload.file_id) throw new Error('file_id is required');
return payload;
